-- Update Unknown daily records with Google Ads attribution
-- Method: Weeks 9-14 Google rate (31%) applied with confidence scaling
-- CONV days: full 31% rate | ACTIVE days (5+ clicks): 60% of rate | LOW: 30% | NO ADS: 0%

DELETE FROM "ClientJob" WHERE "clientId" = 'cl27d7c19cf5525842f021b6e' AND "leadSource" IS NULL;


SELECT "leadSource", count(*), round(sum(total)::numeric, 2) as revenue FROM "ClientJob" WHERE "clientId" = 'cl27d7c19cf5525842f021b6e' GROUP BY "leadSource" ORDER BY revenue DESC LIMIT 15;